class Solution:
    def diagonalSort(self, mat):
        """
        :type mat: List[List[int]]
        :rtype: List[List[int]]
        """
        from collections import defaultdict

        m, n = len(mat), len(mat[0])
        diagonals = defaultdict(list)

        # Group by diagonal (i-j is constant)
        for i in range(m):
            for j in range(n):
                diag_id = i - j
                diagonals[diag_id].append(mat[i][j])

        # Sort each diagonal
        for diag_id in diagonals:
            diagonals[diag_id].sort()

        # Reconstruct matrix
        for i in range(m):
            for j in range(n):
                diag_id = i - j
                mat[i][j] = diagonals[diag_id].pop(0)

        return mat
